function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    const A: number[] = new Array(n);
    const B: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        A[i] = -strategy[i] * prices[i];
        B[i] = (1 - strategy[i]) * prices[i];
    }

    const prefixA: number[] = new Array(n + 1);
    const prefixB: number[] = new Array(n + 1);
    prefixA[0] = 0;
    prefixB[0] = 0;
    for (let i = 0; i < n; i++) {
        prefixA[i + 1] = prefixA[i] + A[i];
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    let maxDelta = 0;
    const halfK = k / 2;
    for (let i = 0; i <= n - k; i++) {
        const sumA = prefixA[i + halfK] - prefixA[i];
        const sumB = prefixB[i + k] - prefixB[i + halfK];
        const delta = sumA + sumB;
        if (delta > maxDelta) {
            maxDelta = delta;
        }
    }

    return originalProfit + Math.max(0, maxDelta);
}

